-- paperPositions: sessionId index + composite userId+sessionId+status
CREATE INDEX IF NOT EXISTS paperPositions_sessionId_idx ON paperPositions (sessionId);
CREATE INDEX IF NOT EXISTS paperPositions_userId_sessionId_status_idx ON paperPositions (userId, sessionId, status);

-- paperTrades: sessionId index + composite userId+sessionId
CREATE INDEX IF NOT EXISTS paperTrades_sessionId_idx ON paperTrades (sessionId);
CREATE INDEX IF NOT EXISTS paperTrades_userId_sessionId_idx ON paperTrades (userId, sessionId);

-- paperEquitySnapshots: sessionId index + composite userId+sessionId
CREATE INDEX IF NOT EXISTS paperEquitySnapshots_sessionId_idx ON paperEquitySnapshots (sessionId);
CREATE INDEX IF NOT EXISTS paperEquitySnapshots_userId_sessionId_idx ON paperEquitySnapshots (userId, sessionId);

-- priceAlerts: triggered+dismissed composite
CREATE INDEX IF NOT EXISTS priceAlerts_triggered_dismissed_idx ON priceAlerts (triggered, dismissed);
CREATE INDEX IF NOT EXISTS priceAlerts_userId_triggered_dismissed_idx ON priceAlerts (userId, triggered, dismissed);

-- userAssets: userId+archived composite
CREATE INDEX IF NOT EXISTS userAssets_userId_idx ON userAssets (userId);
CREATE INDEX IF NOT EXISTS userAssets_userId_archived_idx ON userAssets (userId, archived);

